mapper.select:
WITH UnionData AS ( -- 전월 기말 (EOH) SELECT FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') AS YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, STOCK, 0 AS BOH, ISNULL(EOH, 0) AS EOH FROM DOI_STOCK WHERE FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') =
#{yyyymm}
FORMAT(GETDATE(), 'yyyyMM')
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
UNION ALL
-- 당월 기초 (BOH) SELECT YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, STOCK, ISNULL(BOH, 0) AS BOH, 0 AS EOH FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
) SELECT YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, STOCK, SUM(BOH) AS BOH, SUM(EOH) AS PREV_EOH, SUM(BOH) - SUM(EOH) AS 차이수량, CASE WHEN SUM(EOH) = 0 THEN '전월 데이터 없음' WHEN ABS(SUM(BOH) - SUM(EOH)) > 0.01 THEN '불일치' ELSE '정상' END AS 상태 FROM UnionData GROUP BY YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, STOCK ORDER BY MODEL, YYYYMM

SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN ABS((ISNULL(BOH, 0) + ISNULL([INPUT], 0)) - (ISNULL([OUT], 0) + ISNULL(EOH, 0))) <= 0.01 THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN ABS((ISNULL(BOH, 0) + ISNULL([INPUT], 0)) - (ISNULL([OUT], 0) + ISNULL(EOH, 0))) > 0.01 THEN 1 ELSE 0 END) AS ERROR_COUNT, 0 AS WARNING_COUNT FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}

WITH UnionData AS ( -- 전월 기말 (EOH) SELECT FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') AS YYYYMM, SITE, MODEL, MODEL_TYPE, STOCK, 0 AS BOH, ISNULL(EOH, 0) AS EOH FROM DOI_STOCK WHERE FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') =
#{yyyymm}
FORMAT(GETDATE(), 'yyyyMM')
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
UNION ALL
-- 당월 기초 (BOH) SELECT YYYYMM, SITE, MODEL, MODEL_TYPE, STOCK, ISNULL(BOH, 0) AS BOH, 0 AS EOH FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
), ContinuityData AS ( SELECT YYYYMM, SUM(BOH) AS BOH, SUM(EOH) AS PREV_EOH, CASE WHEN SUM(EOH) = 0 THEN '전월 데이터 없음' WHEN ABS(SUM(BOH) - SUM(EOH)) > 0.01 THEN '불일치' ELSE '정상' END AS 상태 FROM UnionData GROUP BY YYYYMM, SITE, MODEL, MODEL_TYPE, STOCK ) SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN 상태 = '정상' THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN 상태 = '불일치' THEN 1 ELSE 0 END) AS MISMATCH_COUNT, SUM(CASE WHEN 상태 = '전월 데이터 없음' THEN 1 ELSE 0 END) AS NO_DATA_COUNT FROM ContinuityData
